using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=gc();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
int n;
int p[100005],ans,t;
signed main(void)
{
	n=read();
	for(int i=0;i*i<=n;i++)
	{
		p[++t]=i*i;
	}
	FOR(i,1,t)
	{
		FOR(j,1,t)
		{
			if(p[i]+p[j]>n)break;
			FOR(l,1,t)
			{
				if(p[i]+p[j]+p[l]>n)break;
				int tmp=n-p[i]-p[j]-p[l];
				int s=floor(sqrt(tmp));
				if(s*s==tmp)ans++;
			}
		}
	}
	writeln(ans);
	return 0;
}
